function updateCharacterCard(char, i) {
  const card = document.getElementById(`char-${i}`);
  if (!card) return;

  const targetName = char.interactTarget
    ? (simEngine.objectEngine.getById(char.interactTarget)?.name ?? char.interactTarget)
    : char.targetObjectId
      ? (simEngine.objectEngine.getById(char.targetObjectId)?.name ?? char.targetObjectId)
      : '—';

  // Hold countdown timer (shown while character is locked at an object)
  let holdHtml = '';
  if (char.action === 'interacting' && char.interactTimer > 0 && char.interactTimerMax > 0) {
    const pct = Math.max(0, Math.min(100, (1 - char.interactTimer / char.interactTimerMax) * 100));
    holdHtml = `
      <div class="char-row" style="margin-top:4px">
        <span>Hold</span>
        <span class="char-value">${Math.ceil(char.interactTimer / 1000)}s</span>
      </div>
      <div class="stat-bar">
        <div class="stat-fill hold-timer" style="width:${pct.toFixed(1)}%"></div>
      </div>
    `;
  }

