import { Character } from './src/Character.js';

// Test basic Character construction with new fields
const walkable = Array.from({ length: 13 }, () => Array(19).fill(true));
const char = new Character({
  name: 'Test', label: 'Tester',
  tx: 5, ty: 5,
  walkable, gridCols: 19, gridRows: 13,
});

console.assert(char.action === 'idle', 'action should be idle');
console.assert(char.talkTimer === 0, 'talkTimer should be 0');
console.assert(char.talkTimerMax === 0, 'talkTimerMax should be 0');
console.assert(char.talkTarget === null, 'talkTarget should be null');
console.assert(char.pendingTalkTarget === null, 'pendingTalkTarget should be null');
console.assert(char.pendingTalkDialogue === null, 'pendingTalkDialogue should be null');
console.assert(char.pendingTalkResponse === null, 'pendingTalkResponse should be null');
console.assert(typeof char.startTalk === 'function', 'startTalk should be a function');

// Test startTalk
const partner = new Character({
  name: 'Partner', label: 'Par',
  tx: 6, ty: 5,
  walkable, gridCols: 19, gridRows: 13,
});

char.startTalk(partner, 12000);
console.assert(char.action === 'talking', `action should be talking, got ${char.action}`);
console.assert(char.talkTimer === 12000, 'talkTimer should be 12000');
console.assert(char.talkTarget === partner, 'talkTarget should be partner');

// Test update in talking state
char.update(5000);
console.assert(char.action === 'talking', 'still talking after 5s');
console.assert(char.talkTimer < 12000, 'talkTimer should have decreased');

char.update(7100); // total > 12000
console.assert(char.action === 'idle', `should be idle after timer expires, got ${char.action}`);
console.assert(char.talkTarget === null, 'talkTarget should be cleared');

console.log('All Character tests passed!');
EOF

