import { SimulationEngine } from './src/Engine.js';
import { Character } from './src/Character.js';

const GRID_COLS = 19, GRID_ROWS = 13;
const walkable = Array.from({ length: GRID_ROWS }, () => Array(GRID_COLS).fill(true));

const engine = new SimulationEngine({ walkable, gridCols: GRID_COLS, gridRows: GRID_ROWS });

const charA = new Character({ name: 'Amelia', label: 'Maple', tx: 5, ty: 5, walkable, gridCols: GRID_COLS, gridRows: GRID_ROWS });
const charB = new Character({ name: 'Lucy', label: 'Sol', tx: 7, ty: 5, walkable, gridCols: GRID_COLS, gridRows: GRID_ROWS });
engine.addCharacter(charA);
engine.addCharacter(charB);

// Simulate AIEngine setting up talk target
charA.pendingTalkTarget = charB;
charA.pendingTalkDialogue = 'Hello!';
charA.pendingTalkResponse = 'Hi there!';

// Both are idle — should start conversation
engine._handleTalkArrival(charA);

console.assert(charA.action === 'talking', `charA should be talking, got ${charA.action}`);
console.assert(charB.action === 'talking', `charB should be talking, got ${charB.action}`);
console.assert(charA.talkTarget === charB, 'charA.talkTarget should be charB');
console.assert(charB.talkTarget === charA, 'charB.talkTarget should be charA');
console.assert(charA.pendingTalkTarget === null, 'pendingTalkTarget cleared');
console.assert(charA.pendingSpeech === 'Hello!', `charA pendingSpeech should be 'Hello!', got ${charA.pendingSpeech}`);
console.assert(charB.pendingSpeech === 'Hi there!', `charB pendingSpeech should be 'Hi there!', got ${charB.pendingSpeech}`);
console.assert(engine.pendingEvents.some(e => e.type === 'conversation_start'), 'conversation_start event should be pushed');

console.log('Conversation start test passed!');

// Reset and test rejection
charA.action = 'idle';
charA.talkTarget = null;
charB.action = 'interacting'; // B is busy now

const charC = new Character({ name: 'Ash', label: 'Nyx', tx: 3, ty: 5, walkable, gridCols: GRID_COLS, gridRows: GRID_ROWS });
engine.addCharacter(charC);
engine.pendingEvents.length = 0; // clear

charC.pendingTalkTarget = charB;
engine._handleTalkArrival(charC);

console.assert(charC.action === 'idle', `charC should stay idle, got ${charC.action}`);
console.assert(charB.action === 'interacting', 'charB should still be interacting');
console.assert(engine.pendingEvents.some(e => e.type === 'talk_rejected'), 'talk_rejected event should be pushed');

console.log('Rejection test passed!');
console.log('All Engine tests passed!');
EOF

node --input-type=module <<'EOF'
import { AIEngine } from './src/AIEngine.js';
import { Character } from './src/Character.js';

const GRID_COLS = 19, GRID_ROWS = 13;
const walkable = Array.from({ length: GRID_ROWS }, (_, row) =>
  Array.from({ length: GRID_COLS }, (_, col) =>
    col >= 1 && col <= 17 && row >= 2 && row <= 9
  )
);

const engine = new AIEngine({ endpoint: null }); // disabled

const charA = new Character({ name: 'Amelia', label: 'Maple', tx: 5, ty: 5, walkable, gridCols: GRID_COLS, gridRows: GRID_ROWS });
const charB = new Character({ name: 'Lucy', label: 'Sol', tx: 7, ty: 5, walkable, gridCols: GRID_COLS, gridRows: GRID_ROWS });

const events = [];
const simState = {
  timeString: '10:00 AM',
  findAdjacentWalkable: (tx, ty) => {
    const dirs = [{ tx, ty: ty - 1 }, { tx, ty: ty + 1 }, { tx: tx - 1, ty }, { tx: tx + 1, ty }];
    return dirs.find(d => walkable[d.ty]?.[d.tx]) ?? null;
  },
  pushEvent: (ev) => events.push(ev),
};

// Test 1: talk to idle charB — should succeed (set pendingTalkTarget)
engine._applyDecision(charA, {
  action: 'talk',
  targetCharacter: 'Sol',
  dialogue: 'Hey Sol!',
  targetDialogue: 'Hey Maple!',
}, [charA, charB], [], simState);

console.assert(charA.pendingTalkTarget === charB, `pendingTalkTarget should be charB, got ${charA.pendingTalkTarget}`);
console.assert(charA.action === 'walking', `charA should be walking, got ${charA.action}`);
console.assert(charA.pendingTalkDialogue === 'Hey Sol!', 'dialogue stored');
console.assert(charA.pendingTalkResponse === 'Hey Maple!', 'response stored');
console.assert(events.length === 0, 'no rejection events for accepted talk');
console.log('Talk accepted test passed!');

// Reset
charA.path = [];
charA.action = 'idle';
charA.pendingTalkTarget = null;
events.length = 0;

// Test 2: talk to busy charB — should reject
charB.action = 'interacting';
engine._applyDecision(charA, {
  action: 'talk',
  targetCharacter: 'Sol',
  dialogue: 'Hey Sol!',
}, [charA, charB], [], simState);

console.assert(charA.pendingTalkTarget === null, 'no pendingTalkTarget when rejected');
console.assert(charA.action === 'idle', `charA stays idle when rejected, got ${charA.action}`);
console.assert(events.some(e => e.type === 'talk_rejected'), 'talk_rejected pushed to events');
console.log('Talk rejected test passed!');

// Test 3: timer pauses during talking
const ai2 = new AIEngine({ endpoint: 'http://fake', decisionIntervalMs: 5000 });
charA.action = 'talking';
ai2._timers.set(charA.name, -100); // timer expired
let decideCalled = false;
ai2._requestDecision = () => { decideCalled = true; };
ai2.update(100, [charA], [], simState);
console.assert(!decideCalled, 'AI decision should NOT fire while talking');
charA.action = 'idle';
ai2.update(100, [charA], [], simState);
console.assert(decideCalled, 'AI decision SHOULD fire when idle');
console.log('AI timer pause test passed!');

console.log('All AIEngine tests passed!');
EOF
